package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testGetQuoteCharacter() throws Exception {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Set up the expected quote character
        char expectedQuoteCharacter = '"';

        // Set the quote character using reflection
        Field quoteCharacterField = CSVFormat.class.getDeclaredField("quoteCharacter");
        quoteCharacterField.setAccessible(true);
        quoteCharacterField.set(csvFormat, expectedQuoteCharacter);

        // Mock the behavior of the getQuoteCharacter method
        when(csvFormat.getQuoteCharacter()).thenReturn(expectedQuoteCharacter);

        // Call the getQuoteCharacter method and assert the result
        assertEquals(expectedQuoteCharacter, csvFormat.getQuoteCharacter());
    }
}
